import sys

def main():
    input = sys.stdin.read
    data = input().split()
    idx = 0
    n = int(data[idx])
    m = int(data[idx+1])
    idx += 2
    grid = []
    for _ in range(n):
        grid.append(data[idx])
        idx += 1
    q = int(data[idx])
    idx += 1
    queries = []
    for _ in range(q):
        x1 = int(data[idx])
        x2 = int(data[idx+1])
        queries.append((x1-1, x2-1))
        idx += 2

    # Precompute prefix sums for each row
    prefix = [[0]*(m+1) for _ in range(n)]
    for i in range(n):
        for j in range(m):
            prefix[i][j+1] = prefix[i][j] + (1 if grid[i][j] == 'X' else 0)

    # Precompute the earliest column where a cell is 'X' in each row
    earliest = [m] * n
    for i in range(n):
        for j in range(m):
            if grid[i][j] == 'X':
                earliest[i] = j
                break

    # Function to check if a subgrid is determinable
    def is_determinable(x1, x2):
        for i in range(n):
            # Check if there is any 'X' in the subgrid
            if prefix[i][x2+1] - prefix[i][x1] > 0:
                # Check if the earliest 'X' is within the subgrid
                if earliest[i] < x1 or earliest[i] > x2:
                    return False
        return True

    for x1, x2 in queries:
        if is_determinable(x1, x2):
            print("YES")
        else:
            print("NO")

if __name__ == "__main__":
    main()

